const input = $json ?? {};
const message = input.message ?? {};
const callback = input.callback_query ?? null;
const callbackData = callback?.data ? String(callback.data) : '';
const messageText = typeof message.text === 'string' ? message.text : '';
const callbackText = typeof callback?.message?.text === 'string' ? callback.message.text : '';
const text = messageText || callbackText || '';
const chatIdRaw = message.chat?.id ?? callback?.message?.chat?.id ?? '';
const userIdRaw = message.from?.id ?? callback?.from?.id ?? '';
const messageIdRaw = message.message_id ?? callback?.message?.message_id ?? callback?.id ?? '';
const startMatch = text.match(/^\/start(?:\s+(.+))?$/);
const deepLink = startMatch?.[1] ? String(startMatch[1]).trim() : null;
let eventType = 'text_message';
if (callback) {
  eventType = 'callback_action';
} else if (startMatch) {
  eventType = deepLink ? 'deep_link_start' : 'start_reset';
}
return [{
  json: {
    event: {
      event_type: eventType,
      text,
      chatId: String(chatIdRaw || ''),
      chat_id: String(chatIdRaw || ''),
      userId: String(userIdRaw || ''),
      messageId: String(messageIdRaw || ''),
      timestamp: Date.now(),
      callback_query: callbackData ? { data: callbackData } : null,
      deep_link: deepLink,
    },
  },
}];

const payload = $json ?? {};
let event = payload.event ?? null;

const readEventFromNode = (nodeName) => {
  try {
    const nodeRef = $(nodeName);
    if (!nodeRef || !nodeRef.isExecuted) return null;
    const candidate = nodeRef.first()?.json?.event;
    return candidate && typeof candidate === 'object' ? candidate : null;
  } catch {
    return null;
  }
};

if (!event || typeof event !== 'object') {
  event = readEventFromNode('Event Normalizer')
    ?? readEventFromNode('Event Loader')
    ?? readEventFromNode('Unify Payload')
    ?? readEventFromNode('Telegram Input')
    ?? readEventFromNode('Telegram Trigger')
    ?? null;
}

if (!event || typeof event !== 'object') {
  event = { chatId: 0, error: 'trigger_event_lost' };
  console.log(JSON.stringify({
    node: 'Session Bootstrap',
    warning: 'trigger_event_lost',
    fallback_nodes: ['Event Normalizer', 'Event Loader', 'Unify Payload', 'Telegram Input', 'Telegram Trigger'],
  }));
}

event = event && typeof event === 'object' ? event : {};
const isStartReset = event.event_type === 'start_reset' || event.event_type === 'deep_link_start';
const remoteEnvelope = payload.session && typeof payload.session === 'object'
  ? payload.session
  : (payload.data?.session && typeof payload.data.session === 'object' ? payload.data.session : null);
const remoteData = remoteEnvelope && Object.prototype.hasOwnProperty.call(remoteEnvelope, 'data')
  ? remoteEnvelope.data
  : (payload.session?.data ?? payload.data?.session?.data ?? remoteEnvelope);
const existing = remoteData && typeof remoteData === 'object' ? remoteData : {};
const now = Date.now();
const history = Array.isArray(existing.conversation_history)
  ? existing.conversation_history
  : (Array.isArray(existing.message_history) ? existing.message_history : []);
const shownProducts = Array.isArray(existing.flow_context?.buy_flow?.shown_products)
  ? existing.flow_context.buy_flow.shown_products
  : (Array.isArray(existing.shown_options) ? existing.shown_options : []);
const currentInterest = existing.flow_context?.buy_flow?.current_interest
  ?? existing.active_product_id
  ?? existing.selected_option
  ?? null;
const currentTopic = existing.conversation_state?.current_topic ?? existing.last_topic ?? null;
const currentFlow = existing.conversation_state?.current_flow ?? existing.resolved_flow ?? null;
const active = existing.conversation_state?.is_active;
const baseCount = Number.isFinite(Number(existing.message_count))
  ? Number(existing.message_count)
  : history.filter((item) => item && typeof item === 'object').length;
const normalizeText = (value) => typeof value === 'string' && value.trim() ? value.trim() : null;
const normalizeBudget = (value) => {
  const numeric = Number(value);
  return Number.isFinite(numeric) ? numeric : null;
};
const currentInterestRecord = currentInterest && typeof currentInterest === 'object' ? currentInterest : {};
const existingConstraints = existing.collected_constraints && typeof existing.collected_constraints === 'object'
  ? existing.collected_constraints
  : {};
const collected_constraints = {
  budget_etb: normalizeBudget(existingConstraints.budget_etb ?? existing.budget_etb ?? null),
  brand: normalizeText(existingConstraints.brand ?? currentInterestRecord.brand ?? null),
  model: normalizeText(existingConstraints.model ?? currentInterestRecord.model ?? currentInterestRecord.name ?? null),
  storage: normalizeText(existingConstraints.storage ?? currentInterestRecord.storage ?? null),
  condition: normalizeText(existingConstraints.condition ?? currentInterestRecord.condition ?? null),
};
const session = {
  session_id: String(existing.session_id ?? ('sess_' + String(event.userId ?? event.chatId ?? 'guest'))),
  customer_id: String(existing.customer_id ?? event.userId ?? ''),
  created_at: Number.isFinite(Number(existing.created_at)) ? Number(existing.created_at) : now,
  last_message_at: now,
  message_count: isStartReset ? 0 : Math.max(0, baseCount),
  conversation_history: isStartReset ? [] : history.slice(-12).filter((item) => item && typeof item === 'object'),
  conversation_state: {
    current_topic: isStartReset ? null : currentTopic,
    current_flow: isStartReset ? null : currentFlow,
    is_active: typeof active === 'boolean' ? active : true,
  },
  flow_context: {
    buy_flow: {
      shown_products: isStartReset ? [] : shownProducts,
      current_interest: isStartReset ? null : currentInterest,
    },
  },
  collected_constraints: isStartReset
    ? { budget_etb: null, brand: null, model: null, storage: null, condition: null }
    : collected_constraints,
  last_asked_key: isStartReset ? null : normalizeText(existing.last_asked_key ?? existing.last_asked_field ?? null),
  admin_escalation: existing.admin_escalation && typeof existing.admin_escalation === 'object'
    ? {
        required: Boolean(existing.admin_escalation.required),
        reason: existing.admin_escalation.reason ?? null,
        status: existing.admin_escalation.status ?? null,
      }
    : {
        required: false,
        reason: null,
        status: null,
      },
};
// Read adminSettings from the upstream Session Load Convex response
const rawAdminSettings = (() => {
  // adminSettings comes in through Session Load node's json output
  try {
    const loaded = $('Session Load').first()?.json;
    if (loaded && loaded.adminSettings && typeof loaded.adminSettings === 'object') {
      return loaded.adminSettings;
    }
  } catch {}
  return null;
})();

const client_config = {
  "store_name": $env.STORE_NAME || rawAdminSettings?.storeName || $json.store_name || "TedyTech",
  "default_language": $env.DEFAULT_LANG || "am",
  "supports_exchange": true,
  "supports_finance": false,
  "telegram_bot_name": $env.BOT_NAME || $json.bot_name || "TedyTech Bot",
  "sellerId": $env.SELLER_ID || $json.seller_id || null,
  "store_address": rawAdminSettings?.storeAddress || null,
  "store_location_link": rawAdminSettings?.storeLocationLink || null,
  "support_contact": rawAdminSettings?.supportContact || null,
  "warranty_policy": rawAdminSettings?.warrantyPolicy || null,
  "exchange_rules": rawAdminSettings?.exchangeRules || null,
};
return [{
  json: {
    event,
    session,
    client_config,
    session_source: remoteEnvelope?.exists ? 'remote' : 'bootstrap',
  },
}];

const SESSION_BOOTSTRAP_NODE = 'Session Bootstrap';
const base = (() => {
  try {
    const ref = $item(0).$node[SESSION_BOOTSTRAP_NODE].json;
    if (!ref || typeof ref !== 'object') {
      console.error(JSON.stringify({ node: 'Understanding JSON Guard', error: 'cross_node_ref_empty', ref_node: SESSION_BOOTSTRAP_NODE }));
      return {};
    }
    return ref;
  } catch (e) {
    console.error(JSON.stringify({ node: 'Understanding JSON Guard', error: 'cross_node_ref_failed', ref_node: SESSION_BOOTSTRAP_NODE, message: e.message }));
    return {};
  }
})();
const payload = $json ?? {};
const event = base.event && typeof base.event === 'object' ? base.event : {};
const session = base.session && typeof base.session === 'object' ? base.session : {};
const client_config = base.client_config && typeof base.client_config === 'object' ? base.client_config : {};

const allowedMessageFunctions = ['info_request', 'refinement', 'negotiation', 'acknowledgment', 'clarification', 'fresh_request'];
const allowedBusinessIntents = ['store_info', 'product_search', 'pricing', 'exchange', 'support'];
const allowedTopics = ['store_info', 'product', 'exchange', 'pricing', 'location'];
const hardFallback = {
  message_function: 'clarification',
  business_intent: null,
  topic: null,
  confidence: 0.0,
  ambiguity: 1.0,
  missing_information: [],
  reference_resolution: {
    refers_to: null,
    resolved_id: null,
  },
  last_asked_key: null,
};

const issues = [];
const isRecord = (value) => !!value && typeof value === 'object' && !Array.isArray(value);
const parseJsonObject = (value) => {
  if (!value) return null;
  if (isRecord(value)) return value;
  if (typeof value !== 'string' || !value.trim()) return null;
  try {
    const parsed = JSON.parse(value);
    return isRecord(parsed) ? parsed : null;
  } catch {
    return null;
  }
};
const normalizeEnum = (value, allowed, label) => {
  if (typeof value !== 'string') {
    issues.push(label + '_type');
    return null;
  }
  const normalized = value.trim().toLowerCase();
  if (!allowed.includes(normalized)) {
    issues.push(label + '_invalid');
    return null;
  }
  return normalized;
};
const normalizeNullableEnum = (value, allowed, label) => {
  if (value === null || value === undefined) return null;
  return normalizeEnum(value, allowed, label);
};
const normalizeUnitNumber = (value, label) => {
  if (typeof value !== 'number' || !Number.isFinite(value)) {
    issues.push(label + '_type');
    return null;
  }
  if (value < 0 || value > 1) {
    issues.push(label + '_range');
    return null;
  }
  return value;
};
const normalizeStringArray = (value, label) => {
  if (!Array.isArray(value)) {
    issues.push(label + '_type');
    return null;
  }
  const normalized = [];
  for (const item of value) {
    if (typeof item !== 'string') {
      issues.push(label + '_item_type');
      return null;
    }
    const text = item.trim();
    if (text) normalized.push(text);
  }
  return normalized;
};
const normalizeNullableString = (value, label) => {
  if (value === null || value === undefined) return null;
  if (typeof value !== 'string') {
    issues.push(label + '_type');
    return null;
  }
  const normalized = value.trim();
  return normalized || null;
};
const validateReferenceResolution = (value) => {
  if (!isRecord(value)) {
    issues.push('reference_resolution_type');
    return null;
  }
  return {
    refers_to: normalizeNullableString(value.refers_to, 'reference_resolution.refers_to'),
    resolved_id: normalizeNullableString(value.resolved_id, 'reference_resolution.resolved_id'),
  };
};

const rawResponse = parseJsonObject(payload.choices?.[0]?.message?.content)
  || parseJsonObject(payload.output_text)
  || parseJsonObject(payload.text)
  || parseJsonObject(payload.data)
  || parseJsonObject(payload.result)
  || parseJsonObject(payload);

let understanding_output = hardFallback;
if (!rawResponse) {
  issues.push('understanding_response_not_parseable');
} else {
  const validated = {
    message_function: normalizeEnum(rawResponse.message_function, allowedMessageFunctions, 'message_function'),
    business_intent: normalizeNullableEnum(rawResponse.business_intent, allowedBusinessIntents, 'business_intent'),
    topic: normalizeNullableEnum(rawResponse.topic, allowedTopics, 'topic'),
    confidence: normalizeUnitNumber(rawResponse.confidence, 'confidence'),
    ambiguity: normalizeUnitNumber(rawResponse.ambiguity, 'ambiguity'),
    missing_information: normalizeStringArray(rawResponse.missing_information, 'missing_information'),
    reference_resolution: validateReferenceResolution(rawResponse.reference_resolution),
    last_asked_key: normalizeNullableString(rawResponse.last_asked_key, 'last_asked_key'),
  };

  const validationFailed = [
    validated.message_function,
    validated.confidence,
    validated.ambiguity,
    validated.missing_information,
    validated.reference_resolution,
  ].some((value) => value === null) || issues.length > 0;

  if (!validationFailed) {
    understanding_output = {
      message_function: validated.message_function,
      business_intent: validated.business_intent,
      topic: validated.topic,
      confidence: validated.confidence,
      ambiguity: validated.ambiguity,
      missing_information: validated.missing_information,
      reference_resolution: validated.reference_resolution,
      last_asked_key: validated.last_asked_key,
    };
  }
}

const understanding_meta = {
  validator_mode: 'pure_schema_validator',
  schema_mode: 'minimal_guard_v2',
  valid: issues.length === 0,
  issues,
  raw_response: rawResponse,
  fallback_applied: issues.length > 0,
  timestamp: Date.now(),
};
console.log(JSON.stringify({
  node: 'Understanding JSON Guard - Pure Validator',
  valid: understanding_meta.valid,
  fallback_applied: understanding_meta.fallback_applied,
  issues: understanding_meta.issues,
  raw_response: rawResponse,
}));

return [{
  json: {
    event,
    session,
    client_config,
    understanding_output,
    understanding_meta,
  },
}];

const input = $json ?? {};
const event = input.event && typeof input.event === 'object' ? input.event : {};
const session = input.session && typeof input.session === 'object' ? input.session : {};
const client_config = input.client_config && typeof input.client_config === 'object' ? input.client_config : {};
const understanding_output = input.understanding_output && typeof input.understanding_output === 'object' ? input.understanding_output : {};
const understanding_meta = input.understanding_meta && typeof input.understanding_meta === 'object' ? input.understanding_meta : {};

const isRecord = (value) => !!value && typeof value === 'object' && !Array.isArray(value);
const normalizeText = (value) => typeof value === 'string' && value.trim() ? value.trim() : null;
const normalizeNullableNumber = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const numeric = Number(value);
  return Number.isFinite(numeric) ? numeric : null;
};
const normalizePositiveNumber = (value) => {
  const numeric = normalizeNullableNumber(value);
  return numeric !== null && numeric > 0 ? numeric : null;
};
const normalizeStringArray = (value) => Array.isArray(value)
  ? value.filter((item) => typeof item === 'string' && item.trim()).map((item) => item.trim())
  : [];
const normalizeProduct = (value, index) => {
  if (value === null || value === undefined) return null;
  if (typeof value === 'string' || typeof value === 'number') {
    return { id: String(value), brand: null, model: null, storage: null, condition: null, price_etb: null, name: String(value), raw: value, index };
  }
  if (!isRecord(value)) return null;
  const priceValue = value.price_etb ?? value.price ?? value.amount ?? null;
  return {
    id: String(value.id ?? value.product_id ?? value.sku ?? ('product_' + index)),
    brand: normalizeText(value.brand),
    model: normalizeText(value.model ?? value.name ?? value.title),
    storage: normalizeText(value.storage),
    condition: normalizeText(value.condition),
    price_etb: normalizeNullableNumber(priceValue),
    name: [value.brand, value.model].filter(Boolean).join(' ').trim() || normalizeText(value.name ?? value.title),
    raw: value,
    index,
  };
};

const shownProducts = Array.isArray(session.flow_context?.buy_flow?.shown_products)
  ? session.flow_context.buy_flow.shown_products.map(normalizeProduct).filter(Boolean)
  : [];
const currentInterest = normalizeProduct(session.flow_context?.buy_flow?.current_interest, shownProducts.length + 1);
const currentFlow = session.conversation_state?.current_flow ?? null;
const currentTopic = session.conversation_state?.current_topic ?? null;
const existingConstraintsSource = isRecord(session.collected_constraints) ? session.collected_constraints : {};
const mergedConstraints = {
  budget_etb: normalizePositiveNumber(existingConstraintsSource.budget_etb),
  brand: normalizeText(existingConstraintsSource.brand ?? currentInterest?.brand ?? null),
  model: normalizeText(existingConstraintsSource.model ?? currentInterest?.model ?? null),
  storage: normalizeText(existingConstraintsSource.storage ?? currentInterest?.storage ?? null),
  condition: normalizeText(existingConstraintsSource.condition ?? currentInterest?.condition ?? null),
};

const referenceSource = isRecord(understanding_output.reference_resolution) ? understanding_output.reference_resolution : {};
const reference_resolution = {
  reference_type: normalizeText(referenceSource.refers_to) ?? 'none',
  resolved: Boolean(normalizeText(referenceSource.resolved_id)),
  resolved_product_id: normalizeText(referenceSource.resolved_id),
  resolved_product_name: null,
};
const resolveProductById = (id) => shownProducts.find((item) => item.id === id) ?? (currentInterest?.id === id ? currentInterest : null) ?? null;
const resolvedProduct = reference_resolution.resolved && reference_resolution.resolved_product_id
  ? resolveProductById(reference_resolution.resolved_product_id)
  : null;

const businessIntent = normalizeText(understanding_output.business_intent);
const messageFunction = normalizeText(understanding_output.message_function) ?? 'clarification';
const understandingTopic = normalizeText(understanding_output.topic);
const confidence = typeof understanding_output.confidence === 'number' ? understanding_output.confidence : 0;
const missingInformation = normalizeStringArray(understanding_output.missing_information);
const requestedLastAskedKey = normalizeText(understanding_output.last_asked_key);
const hasActiveContext = Boolean(
  currentFlow
  || currentTopic
  || shownProducts.length > 0
  || currentInterest
  || Object.values(mergedConstraints).some((value) => value !== null)
  || (Array.isArray(session.conversation_history) && session.conversation_history.length > 0)
);
const intentFlow = {
  product_search: 'buy',
  pricing: 'buy',
  exchange: 'exchange',
  store_info: 'info',
  support: 'support',
}[businessIntent ?? ''] ?? null;
const sameFlowIntent = Boolean(
  (currentFlow === 'buy' && ['product_search', 'pricing'].includes(businessIntent ?? ''))
  || (currentFlow === 'exchange' && businessIntent === 'exchange')
  || (currentFlow === 'info' && businessIntent === 'store_info')
  || (currentFlow === 'support' && businessIntent === 'support')
);
const extractModelFromText = (text) => {
  if (typeof text !== 'string') return null;
  const m = text.match(/\b(?:iphone\s*\d+(?:\s*(?:pro\s*max|pro|max|plus|mini))?|samsung\s*[a-z0-9]+(?:\s+[a-z0-9]+)?|pixel\s*[a-z0-9]+|redmi\s*[a-z0-9]+)\b/i);
  return m ? m[0].trim().toLowerCase() : null;
};
const rawTextModel = extractModelFromText(event.text ?? '');
const sessionModelLower = (currentInterest?.model ?? mergedConstraints.model ?? '').toLowerCase() || null;
const isModelSwitch = Boolean(
  rawTextModel
  && sessionModelLower
  && !rawTextModel.includes(sessionModelLower)
  && !sessionModelLower.includes(rawTextModel)
);
const shouldContinueContext = Boolean(
  hasActiveContext && !isModelSwitch && (
    ['refinement', 'negotiation'].includes(messageFunction)
    || reference_resolution.reference_type !== 'none'
    || sameFlowIntent
  )
);
const effectiveFlow = intentFlow ?? currentFlow ?? null;
const effectiveTopic = understandingTopic ?? (shouldContinueContext ? currentTopic ?? null : null);
const hasKnownBudget = mergedConstraints.budget_etb !== null;
const hasKnownBrand = Boolean(mergedConstraints.brand);
const hasKnownModel = Boolean(mergedConstraints.model);
const hasProductContext = Boolean(
  resolvedProduct
  || currentInterest
  || shownProducts.length > 0
  || hasKnownBudget
  || hasKnownBrand
  || hasKnownModel
);

const computedMissingFields = [];
if (effectiveFlow === 'buy' && missingInformation.length === 0) {
  const needFreshProductAnchor = !hasProductContext && !shouldContinueContext;
  if (needFreshProductAnchor) {
    if (hasKnownBrand && !hasKnownModel) computedMissingFields.push('model');
    else if (!hasKnownBrand && !hasKnownModel) computedMissingFields.push('brand_or_model');
  }
}
if (effectiveFlow === 'exchange' && missingInformation.length === 0) {
  const needProductAnchor = !currentInterest && shownProducts.length === 0;
  if (needProductAnchor) {
    if (hasKnownBrand && !hasKnownModel) computedMissingFields.push('model');
    else if (!hasKnownBrand && !hasKnownModel) computedMissingFields.push('brand_or_model');
  }
  if (!mergedConstraints.condition) computedMissingFields.push('condition');
}
const missing_fields = missingInformation.length > 0 ? missingInformation.slice() : computedMissingFields;
if (effectiveFlow === 'exchange' && !mergedConstraints.condition && !missing_fields.includes('condition')) {
  missing_fields.push('condition');
}
if (effectiveFlow === 'exchange' && missing_fields.length > 2) {
  missing_fields.length = 2;
}
const last_asked_key = requestedLastAskedKey ?? missing_fields[0] ?? null;

const productContext = {
  brand: mergedConstraints.brand,
  model: mergedConstraints.model,
  storage: mergedConstraints.storage,
  condition: mergedConstraints.condition,
  budget_etb: mergedConstraints.budget_etb,
  current_interest: currentInterest ? currentInterest.raw : null,
  current_topic: currentTopic,
  current_flow: currentFlow,
};

let rules_output = {
  reply_mode: shouldContinueContext ? 'resume_previous_flow' : 'off_topic_redirect',
  should_call_resolver: false,
  resolver_input: {
    flow: effectiveFlow,
    product_context: productContext,
    missing_fields,
    resolved_reference: resolvedProduct ? { id: resolvedProduct.id, raw: resolvedProduct.raw } : null,
    resolved_product_name: resolvedProduct?.name ?? null,
  },
  session_update: {
    last_topic: effectiveTopic,
    flow_stage: shouldContinueContext ? (currentFlow ?? effectiveFlow) : effectiveFlow,
    ambiguous_reference: reference_resolution.reference_type !== 'none' ? reference_resolution.reference_type : null,
    resolved_ambiguity: reference_resolution.resolved,
    collected_constraints: mergedConstraints,
    last_asked_key,
  },
  confidence,
  reasoning: shouldContinueContext ? 'default_resume_previous_flow' : 'default_off_topic_redirect',
};

if (event.event_type === 'start_reset') {
  rules_output = {
    ...rules_output,
    reply_mode: 'small_talk_redirect',
    should_call_resolver: false,
    session_update: {
      ...rules_output.session_update,
      last_topic: null,
      flow_stage: null,
      ambiguous_reference: null,
      resolved_ambiguity: false,
      last_asked_key: null,
    },
    reasoning: 'start_reset_welcome',
  };
} else if (event.event_type === 'deep_link_start') {
  rules_output = {
    ...rules_output,
    reply_mode: 'business_resolve',
    should_call_resolver: true,
    resolver_input: {
      ...rules_output.resolver_input,
      flow: 'buy',
      missing_fields: [],
    },
    session_update: {
      ...rules_output.session_update,
      last_topic: 'product',
      flow_stage: 'buy',
      last_asked_key: null,
    },
    reasoning: 'deep_link_start_business_entry',
  };
} else if (!Number.isFinite(confidence) || confidence < 0.6) {
  rules_output = {
    ...rules_output,
    reply_mode: shouldContinueContext && currentFlow ? 'resume_previous_flow' : 'handoff_admin',
    should_call_resolver: Boolean(shouldContinueContext && currentFlow),
    reasoning: shouldContinueContext && currentFlow ? 'low_confidence_but_context_preserved' : 'low_understanding_confidence',
  };
} else if (messageFunction === 'acknowledgment') {
  const shouldOpenLightConversation = Boolean(
    Number(session.message_count ?? 0) === 0
    && !currentFlow
    && !currentTopic
    && shownProducts.length === 0
    && !currentInterest
    && !Object.values(mergedConstraints).some((value) => value !== null)
  );
  rules_output = {
    ...rules_output,
    reply_mode: shouldOpenLightConversation ? 'small_talk_redirect' : 'acknowledge_and_close',
    should_call_resolver: false,
    reasoning: shouldOpenLightConversation ? 'acknowledgment_first_turn_redirect' : 'acknowledgment_detected',
  };
} else if (messageFunction === 'clarification') {
  rules_output = {
    ...rules_output,
    reply_mode: hasActiveContext ? 'clarify_reference' : 'handoff_admin',
    should_call_resolver: false,
    reasoning: hasActiveContext ? 'clarification_with_existing_context' : 'clarification_without_context',
  };
} else if (businessIntent === 'store_info' || understandingTopic === 'store_info' || understandingTopic === 'location' || (messageFunction === 'info_request' && (businessIntent === null || businessIntent === 'store_info'))) {
  rules_output = {
    ...rules_output,
    reply_mode: 'business_resolve',
    should_call_resolver: true,
    resolver_input: {
      ...rules_output.resolver_input,
      flow: 'info',
      missing_fields: [],
    },
    session_update: {
      ...rules_output.session_update,
      last_topic: understandingTopic ?? 'store_info',
      flow_stage: shouldContinueContext ? (currentFlow ?? null) : 'info',
      last_asked_key: null,
    },
    reasoning: 'store_info_bypasses_product_flow',
  };
} else if (businessIntent === 'support') {
  rules_output = {
    ...rules_output,
    reply_mode: shouldContinueContext && currentFlow ? 'resume_previous_flow' : 'business_resolve',
    should_call_resolver: true,
    resolver_input: {
      ...rules_output.resolver_input,
      flow: 'support',
      missing_fields: [],
    },
    session_update: {
      ...rules_output.session_update,
      last_topic: understandingTopic ?? 'support',
      flow_stage: shouldContinueContext ? (currentFlow ?? 'support') : 'support',
      last_asked_key: null,
    },
    reasoning: 'support_request_routed',
  };
} else if (messageFunction === 'negotiation') {
  const negotiationFlow = currentFlow === 'exchange' ? 'exchange' : (intentFlow ?? currentFlow ?? 'buy');
  const hasAnchoredContext = Boolean(
    session.flow_context?.buy_flow?.current_interest
  );
  rules_output = {
    ...rules_output,
    reply_mode: hasAnchoredContext ? 'resume_previous_flow' : 'business_resolve',
    should_call_resolver: hasAnchoredContext ? false : true,
    resolver_input: {
      ...rules_output.resolver_input,
      flow: negotiationFlow,
      missing_fields: [],
    },
    session_update: {
      ...rules_output.session_update,
      flow_stage: negotiationFlow,
      last_asked_key: null,
    },
    reasoning: hasAnchoredContext
      ? 'negotiation_anchored_to_existing_interest'
      : (hasProductContext || hasActiveContext ? 'negotiation_business_resolve_with_context' : 'negotiation_business_resolve_without_context'),
  };
} else if (messageFunction === 'refinement') {
  if (!shouldContinueContext) {
    rules_output.resolver_input.product_context = { budget_etb: mergedConstraints.budget_etb, brand: null, model: null, storage: null, condition: null, current_interest: null, current_topic: null, current_flow: null };
    rules_output.session_update.collected_constraints = { budget_etb: mergedConstraints.budget_etb, brand: null, model: null, storage: null, condition: null };
    rules_output.resolver_input.resolved_reference = null;
  }
  rules_output = {
    ...rules_output,
    reply_mode: shouldContinueContext ? 'resume_previous_flow' : 'business_resolve',
    should_call_resolver: true,
    session_update: {
      ...rules_output.session_update,
      flow_stage: shouldContinueContext ? (currentFlow ?? effectiveFlow) : effectiveFlow,
      last_asked_key,
    },
    reasoning: shouldContinueContext ? 'refinement_reuses_session_context' : 'refinement_with_model_switch',
  };
} else if (messageFunction === 'fresh_request') {
  const isBusiness = businessIntent !== null;
  if (isBusiness) {
    rules_output.resolver_input.product_context = { budget_etb: null, brand: null, model: null, storage: null, condition: null, current_interest: null, current_topic: null, current_flow: null };
    rules_output.session_update.collected_constraints = { budget_etb: null, brand: null, model: null, storage: null, condition: null };
    rules_output.resolver_input.resolved_reference = null;
  }
  rules_output = {
    ...rules_output,
    reply_mode: isBusiness ? 'business_resolve' : 'off_topic_redirect',
    should_call_resolver: isBusiness,
    resolver_input: {
      ...rules_output.resolver_input,
      flow: intentFlow ?? effectiveFlow,
    },
    session_update: {
      ...rules_output.session_update,
      flow_stage: intentFlow ?? effectiveFlow,
      last_asked_key,
    },
    reasoning: isBusiness ? 'fresh_business_request' : 'fresh_non_business_message',
  };
}

return [{ json: { event, session, client_config, understanding_output, understanding_meta, rules_output } }];

parameters.jsonBody:
={{ JSON.stringify({
  seller_id: (() => {
    const cfg = $json.client_config;
    if (cfg && typeof cfg.store_name === 'string' && cfg.store_name.trim()) {
      return cfg.store_name.trim().toLowerCase();
    }
    return $env.SELLER_ID || 'missing_seller_id';
  })(),
  phoneType: (() => {
    const cleanPhoneType = (value) => {
      if (typeof value !== 'string') return null;
      const normalized = value
        .replace(/\b(32|64|128|256|512|1024)\s*gb\b/ig, ' ')
        .replace(/\b(iphone|samsung|pixel|redmi|xiaomi|tecno|infinix|oppo|vivo|realme|itel|nokia)(\d)/ig, '$1 $2')
        .replace(/\b(pro)(max)\b/ig, '$1 $2')
        .replace(/\s+/g, ' ')
        .trim();
      return normalized || null;
    };
    const text = String($json.event?.text || '').trim();
    const extractFromText = (value) => {
      const source = String(value || '').trim();
      if (!source) return null;
      const match = source.match(/\b(?:iphone\s*\d+(?:\s*(?:pro\s*max|pro|max|plus|mini))?|samsung\s*[a-z0-9+ ]+|pixel\s*[a-z0-9+ ]+|redmi\s*[a-z0-9+ ]+|xiaomi\s*[a-z0-9+ ]+|tecno\s*[a-z0-9+ ]+|infinix\s*[a-z0-9+ ]+|oppo\s*[a-z0-9+ ]+|vivo\s*[a-z0-9+ ]+|realme\s*[a-z0-9+ ]+|itel\s*[a-z0-9+ ]+|nokia\s*[a-z0-9+ ]+)\b/i);
      return cleanPhoneType(match ? match[0] : null);
    };
    const explicit = cleanPhoneType($json.rules_output?.resolver_input?.resolved_product_name || null);
    if (explicit) return explicit;
    const fromText = extractFromText(text);
    if (fromText) return fromText;
    const ref = $json.understanding_output?.reference_resolution?.refers_to;
    if (typeof ref === 'string') {
      const normalized = cleanPhoneType(ref);
      const blocked = ['desired_phone', 'current_phone', 'last_shown_option', 'cheaper_option', 'previous_selection', 'none'];
      if (normalized && !blocked.includes(normalized.toLowerCase())) return normalized;
    }
    const fromContext = cleanPhoneType(([
      $json.rules_output?.resolver_input?.product_context?.brand,
      $json.rules_output?.resolver_input?.product_context?.model,
    ].filter(Boolean).join(' ').trim() || [
      $json.session?.collected_constraints?.brand,
      $json.session?.collected_constraints?.model,
    ].filter(Boolean).join(' ').trim()));
    if (fromContext) return fromContext;
    return null;
  })(),
  storage: (() => {
    const s = $json.rules_output?.resolver_input?.product_context?.storage
      ?? $json.session?.collected_constraints?.storage
      ?? null;
    if (typeof s !== 'string' || !s.trim()) return null;
    const m = s.match(/\b(32|64|128|256|512|1024)\s*gb\b/i);
    return m ? (m[1] + 'GB') : null;
  })(),
}) }}

parameters.jsCode:
const RULES_NODE = 'Rules Layer';
let base = {};
try {
  let ref = $json;
  if (!ref || !ref.rules_output) {
     try {
       ref = $('Rules Layer').first().json;
     } catch (e2) {}
  }
  if (!ref || !ref.rules_output) {
     try {
       ref = $item(0).$node['Rules Layer'].json;
     } catch (e3) {}
  }
  base = ref ?? {};
} catch (e) {
  console.error(JSON.stringify({ node: 'Business Data Resolver', error: 'cross_node_ref_failed', ref_node: RULES_NODE, message: e.message }));
}
const event = base.event && typeof base.event === 'object' ? base.event : {};
const session = base.session && typeof base.session === 'object' ? base.session : {};
const client_config = base.client_config && typeof base.client_config === 'object' ? base.client_config : {};
const understanding_output = base.understanding_output && typeof base.understanding_output === 'object' ? base.understanding_output : {};
const rules_output = base.rules_output && typeof base.rules_output === 'object' ? base.rules_output : {};
const resolverInput = rules_output.resolver_input && typeof rules_output.resolver_input === 'object' ? rules_output.resolver_input : {};
const inputItems = $input.all().map((item) => item.json ?? {});

const isRecord = (value) => !!value && typeof value === 'object' && !Array.isArray(value);
const normalizeText = (value) => typeof value === 'string' && value.trim() ? value.trim() : null;
const normalizeNullableNumber = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const numeric = Number(value);
  return Number.isFinite(numeric) ? numeric : null;
};
const normalizeStorageValue = (value) => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  if (!trimmed) return null;
  const gbMatch = trimmed.match(/\b(32|64|128|256|512|1024)\b/i);
  return gbMatch ? (gbMatch[1] + 'GB') : trimmed;
};
const extractStorage = (value) => {
  if (typeof value !== 'string') return null;
  const match = value.match(/\b(32|64|128|256|512|1024)\s*gb\b/i);
  return match ? (match[1] + 'GB') : null;
};
const normalizeProduct = (value, index) => {
  if (value === null || value === undefined || !isRecord(value)) return null;
  const priceValue = value.price_etb ?? value.price ?? value.amount ?? null;
  const stockQty = normalizeNullableNumber(value.stockQuantity ?? value.stock_quantity ?? value.stock ?? null);
  const strippedRaw = (() => {
    if (!isRecord(value)) return value;
    // eslint-disable-next-line no-unused-vars
    const { raw: _raw, ...rest } = value;
    return rest;
  })();
  return {
    id: String(value.id ?? value._id ?? value.product_id ?? value.sku ?? ('product_' + index)),
    brand: normalizeText(value.brand),
    model: normalizeText(value.model ?? value.phoneType ?? value.name ?? value.title),
    price_etb: normalizeNullableNumber(priceValue),
    storage: normalizeStorageValue(String(value.storage ?? '')),
    ram: value.ram === null || value.ram === undefined ? null : String(value.ram),
    condition: normalizeText(value.condition),
    stock_status: stockQty === null ? null : (stockQty > 0 ? 'in_stock' : 'out_of_stock'),
    stock_quantity: stockQty,
    raw: strippedRaw,
  };
};
const looksLikeProductRecord = (value) => isRecord(value) && ['id', '_id', 'product_id', 'sku', 'brand', 'model', 'phoneType', 'name', 'title', 'price', 'price_etb', 'amount'].some((key) => Object.prototype.hasOwnProperty.call(value, key));
const collectRemoteProducts = (items) => {
  const flattened = [];
  for (const item of items) {
    if (Array.isArray(item)) {
      flattened.push(...item.filter(looksLikeProductRecord));
      continue;
    }
    if (isRecord(item) && Array.isArray(item.products)) {
      flattened.push(...item.products.filter(looksLikeProductRecord));
      continue;
    }
    if (looksLikeProductRecord(item)) {
      flattened.push(item);
    }
  }
  const deduped = [];
  const seen = new Set();
  for (const value of flattened) {
    const normalized = normalizeProduct(value, deduped.length + 1);
    if (!normalized) continue;
    if (seen.has(normalized.id)) continue;
    seen.add(normalized.id);
    deduped.push(normalized);
  }
  return deduped;
};

const remoteProducts = collectRemoteProducts(inputItems);
let result_mode = remoteProducts.length > 0 ? 'products_found' : 'no_products';
const products = remoteProducts;

const shownProducts = Array.isArray(session.flow_context?.buy_flow?.shown_products)
  ? session.flow_context.buy_flow.shown_products.map(normalizeProduct).filter(Boolean)
  : [];
const currentInterest = normalizeProduct(session.flow_context?.buy_flow?.current_interest, shownProducts.length + 10);
const sessionConstraintsSource = isRecord(session.collected_constraints) ? session.collected_constraints : {};
const sessionConstraints = {
  budget_etb: normalizeNullableNumber(sessionConstraintsSource.budget_etb),
  brand: normalizeText(sessionConstraintsSource.brand ?? currentInterest?.brand ?? null),
  model: normalizeText(sessionConstraintsSource.model ?? currentInterest?.model ?? null),
  storage: normalizeStorageValue(sessionConstraintsSource.storage ?? currentInterest?.storage ?? null),
  condition: normalizeText(sessionConstraintsSource.condition ?? currentInterest?.condition ?? null),
};
const productContextSource = isRecord(resolverInput.product_context) ? resolverInput.product_context : {};
let effectiveConstraints = {
  budget_etb: Object.prototype.hasOwnProperty.call(productContextSource, 'budget_etb') ? normalizeNullableNumber(productContextSource.budget_etb) : sessionConstraints.budget_etb,
  brand: Object.prototype.hasOwnProperty.call(productContextSource, 'brand') ? normalizeText(productContextSource.brand) : sessionConstraints.brand,
  model: Object.prototype.hasOwnProperty.call(productContextSource, 'model') ? normalizeText(productContextSource.model) : sessionConstraints.model,
  storage: Object.prototype.hasOwnProperty.call(productContextSource, 'storage') ? normalizeStorageValue(productContextSource.storage) : (sessionConstraints.storage ?? extractStorage(String(event.text ?? ''))),
  condition: Object.prototype.hasOwnProperty.call(productContextSource, 'condition') ? normalizeText(productContextSource.condition) : sessionConstraints.condition,
};

const candidateProducts = products.length > 0 ? products : shownProducts;
const productNameForMatch = (product) => [product.brand, product.model].filter(Boolean).join(' ').trim().toLowerCase();
let constraintMatchFailed = false;
const isNonProductFlow = resolverInput.flow === 'info' || resolverInput.flow === 'support';
if (products.length > 0) {
  if (effectiveConstraints.model) {
    const hasModelMatch = candidateProducts.some((product) => productNameForMatch(product).includes(effectiveConstraints.model.toLowerCase()));
    if (!hasModelMatch) constraintMatchFailed = true;
  }
  if (effectiveConstraints.brand && !constraintMatchFailed) {
    const hasBrandMatch = candidateProducts.some((product) => product.brand && product.brand.toLowerCase().includes(effectiveConstraints.brand.toLowerCase()));
    if (!hasBrandMatch) constraintMatchFailed = true;
  }
  if (effectiveConstraints.storage) {
    const hasStorageMatch = candidateProducts.some((product) => product.storage && normalizeStorageValue(product.storage) === normalizeStorageValue(effectiveConstraints.storage));
    if (!hasStorageMatch) effectiveConstraints = { ...effectiveConstraints, storage: null };
  }
  if (effectiveConstraints.condition) {
    const hasConditionMatch = candidateProducts.some((product) => product.condition && product.condition.toLowerCase() === effectiveConstraints.condition.toLowerCase());
    if (!hasConditionMatch) effectiveConstraints = { ...effectiveConstraints, condition: null };
  }
}
const requestedName = normalizeText(resolverInput.resolved_product_name)
  ?? ([effectiveConstraints.brand, effectiveConstraints.model].filter(Boolean).join(' ').trim() || null);
let selectedProduct = null;
if (resolverInput.resolved_reference?.id) {
  selectedProduct = candidateProducts.find((product) => product.id === resolverInput.resolved_reference.id) ?? null;
}
if (!selectedProduct && requestedName) {
  const lowered = requestedName.toLowerCase();
  selectedProduct = candidateProducts.find((product) => {
    const name = productNameForMatch(product);
    return Boolean(name) && name === lowered;
  }) ?? null;
}
const isContinuationFlow = ['refinement', 'negotiation'].includes(understanding_output?.message_function ?? '');
if (!selectedProduct && currentInterest && products.length === 0 && isContinuationFlow) {
  const sameModel = effectiveConstraints.model && currentInterest.model && currentInterest.model.toLowerCase() === effectiveConstraints.model.toLowerCase();
  const sameBrand = effectiveConstraints.brand && currentInterest.brand && currentInterest.brand.toLowerCase() === effectiveConstraints.brand.toLowerCase();
  if (!effectiveConstraints.model || sameModel || sameBrand) {
    selectedProduct = currentInterest;
  }
}

const matchesConstraints = (product) => {
  if (!product) return false;
  if (effectiveConstraints.brand && (!product.brand || !product.brand.toLowerCase().includes(effectiveConstraints.brand.toLowerCase()))) return false;
  if (effectiveConstraints.model) {
    const name = productNameForMatch(product);
    if (!name.includes(effectiveConstraints.model.toLowerCase())) return false;
  }
  if (effectiveConstraints.storage && (!product.storage || normalizeStorageValue(product.storage) !== normalizeStorageValue(effectiveConstraints.storage))) return false;
  if (effectiveConstraints.condition && (!product.condition || product.condition.toLowerCase() !== effectiveConstraints.condition.toLowerCase())) return false;
  return true;
};

const filteredProducts = candidateProducts.filter(matchesConstraints);
const effectiveProducts = filteredProducts.length > 0 ? filteredProducts : (products.length > 0 ? candidateProducts : []);
const replyProducts = selectedProduct
  ? [selectedProduct]
  : effectiveProducts.slice(0, 5);
const numericPrices = replyProducts.map((product) => product.price_etb).filter((value) => Number.isFinite(value));
const priceRange = numericPrices.length > 0 ? { min: Math.min(...numericPrices), max: Math.max(...numericPrices) } : null;
let result_type = 'no_match';
let next_step = 'ask_clarification';
let exchange_context = null;
const isExchangeClarification = resolverInput.flow === 'exchange'
  && Array.isArray(resolverInput.missing_fields)
  && resolverInput.missing_fields.length > 0;
const exchangeContext = resolverInput.flow === 'exchange'
  ? {
      current_interest: session.flow_context?.buy_flow?.current_interest ?? null,
      collected_constraints: effectiveConstraints,
    }
  : null;

if (rules_output.reply_mode === 'clarify_reference') {
  result_type = 'clarification_needed';
  next_step = 'ask_clarification';
} else if (isExchangeClarification) {
  result_type = 'clarification_needed';
  next_step = 'ask_clarification';
  exchange_context = exchangeContext;
} else if (resolverInput.flow === 'exchange') {
  result_type = 'exchange_offer';
  next_step = 'ask_clarification';
  exchange_context = exchangeContext;
} else if (resolverInput.flow === 'info' || resolverInput.flow === 'support') {
  result_type = 'store_info';
  result_mode = 'info';
  next_step = 'direct_answer';
} else if (selectedProduct) {
  result_type = 'single_product';
  next_step = 'show_single';
} else if (effectiveProducts.length > 1) {
  result_type = 'multiple_options';
  next_step = 'show_options';
} else if (effectiveProducts.length === 1) {
  result_type = 'single_product';
  next_step = 'show_single';
} else if ((resolverInput.missing_fields ?? []).length > 0) {
  result_type = 'clarification_needed';
  next_step = 'ask_clarification';
}
if (!isNonProductFlow && constraintMatchFailed && result_type !== 'clarification_needed' && result_type !== 'exchange_offer') {
  result_type = 'no_match';
  next_step = 'ask_clarification';
}

const isNewProductFocus = !currentInterest || (replyProducts[0] && replyProducts[0].id !== currentInterest.id);
const post_price_mode =
  result_type === 'single_product'
  && replyProducts.length === 1
  && resolverInput.flow === 'buy'
  && isNewProductFocus
    ? 'price_shown'
    : null;
const exchange_invitation_variant =
  post_price_mode === 'price_shown'
    ? ((Number.isFinite(Number(session.message_count ?? null)) ? Number(session.message_count) : 0) % 4) + 1
    : null;
const product_detail_fields = (() => {
  if (post_price_mode !== 'price_shown' || !replyProducts[0]) return [];
  const product = replyProducts[0];
  const isApple = (product.brand ?? '').toLowerCase() === 'apple' || (product.model ?? '').toLowerCase().includes('iphone');
  return ['storage', 'ram', 'condition']
    .filter((key) => {
      if (key === 'ram' && isApple) return false;
      return product[key] != null;
    })
    .map((key) => ({ key, value: String(product[key]) }));
})();
const exchange_collection = resolverInput.flow === 'exchange'
  ? (() => {
      const target_phone_raw = session.flow_context?.buy_flow?.current_interest;
      const target_phone = isRecord(target_phone_raw)
        ? {
            brand: normalizeText(target_phone_raw.brand ?? null),
            model: normalizeText(target_phone_raw.model ?? target_phone_raw.phoneType ?? null),
            storage: normalizeStorageValue(target_phone_raw.storage ?? null),
          }
        : null;
      const exchangeDetails = isRecord(session.exchange_details) ? session.exchange_details : {};
      const collectedConstraints = isRecord(session.collected_constraints) ? session.collected_constraints : {};
      return {
        target_phone,
        collected: {
          model: normalizeText(exchangeDetails.model ?? collectedConstraints.model ?? null),
          storage: normalizeStorageValue(exchangeDetails.storage ?? collectedConstraints.storage ?? null),
          ram: exchangeDetails.ram === null || exchangeDetails.ram === undefined ? null : String(exchangeDetails.ram),
          condition: normalizeText(exchangeDetails.condition ?? collectedConstraints.condition ?? null),
          battery_health: exchangeDetails.battery_health === null || exchangeDetails.battery_health === undefined ? null : String(exchangeDetails.battery_health),
        },
      };
    })()
  : null;

const resolver_output = {
  result_mode,
  result_type,
  products: replyProducts,
  exchange_context,
  next_step,
  post_price_mode,
  exchange_invitation_variant,
  product_detail_fields,
  exchange_collection,
  facts_for_reply: {
    product_found: Boolean(selectedProduct || replyProducts.length > 0),
    how_many_options: replyProducts.length,
    stock_status: selectedProduct?.stock_status ?? (replyProducts[0]?.stock_status ?? null),
    price_range: priceRange,
  },
};

return [{
  json: {
    event,
    session,
    client_config,
    understanding_output,
    rules_output,
    result_mode,
    products,
    resolver_output,
  },
}];

parameters.jsonBody:
={{ JSON.stringify({
  model: 'google/gemini-3.1-flash-lite-preview',
  temperature: 0.05,
  response_format: { type: 'json_object' },
  messages: [
    { role: 'system', content: "You are Pass 2 Reply AI for the TedyTech Telegram bot.\\nReturn ONLY one valid JSON object with exactly this shape: {\"reply_text\":\"string\"}.\\nDo not add any other keys. Do not explain anything. Do not add markdown fences.\\nUse only the provided customer_text, understanding_output, rules_output, resolver_output, reply_context, last_messages, and client_config.\\nNever invent stock, price, warranty, availability, delivery, location, or shop facts.\\nKeep the reply to max 3 short lines.\\nDefault to natural Amharic in Ethiopic script for conversation.\\nUse English only for brand, model, storage, and product names where natural.\\nDo not produce awkward English-Amharic transliteration.\\nDo not use vague words like technology, electronics, gadgets, or accessories unless the customer explicitly asks for them.\\nPrefer wording around phone, mobile, model, exchange, shop, price, and availability.\\nOne emoji max, and only when the tone is playful.\\nStrict continuity rules:\\n- If reply_context.should_greet is false, never greet, never welcome, and never reopen with a seller introduction.\\n- Only use welcome or greeting opener text on explicit restart or start_reset. Do not use welcome phrasing for normal business turns.\\n- If reply_context.has_active_context is true, continue that context instead of asking a generic buying-or-exchange question.\\n- If the user message is clear, respond to that exact message and do not replace it with a generic opening.\\n- If current_flow or current_topic exists, use it to continue the thread.\\nStrict reply mode rules:\\n- acknowledge_and_close: short close only, no question, no greeting.\\n- off_topic_redirect: short natural redirect only, at most one gentle next-step question, no greeting, and no product-discovery opener. Do not ask what phone or model the customer wants unless the current message itself contains product intent.\\n- small_talk_redirect: short natural acknowledgment plus one neutral TedyTech-help next step, no repeated welcome, and no product-discovery opener.\\n- clarify_reference: ask which one the customer means, no product facts, no generic reopening.\\n- resume_previous_flow: continue the previous thread directly, no restart behavior.\\n- business_resolve: use resolver facts only. If resolver facts are weak, ask one narrow follow-up tied to the actual customer text or current context, or honestly say the exact detail is not available in the current data. Do not pivot into product discovery unless the customer message itself also contains product intent. If understanding_output.message_function is negotiation or understanding_output.business_intent is pricing, stay price-focused and do not reply with a generic acknowledgment. Address the price concern directly, then ask one narrow price/model follow-up if needed.\ If resolver_output.result_type is single_product and resolver_output.facts_for_reply.stock_status is in_stock, do not say unavailable or out of stock. Respond as available and use the grounded price if resolver_output.facts_for_reply.price_range is present. If resolver_output.result_type is no_match, only then say the exact model is not currently available.\n- handoff_admin: brief reassurance only, no question, no greeting.\\nStore-info rules:\\n- If rules_output.resolver_input.flow is info or understanding_output.topic is store_info, answer only the store-info request.\\n- GROUNDED store info is in client_config: store_address contains the physical address, store_location_link is the maps link, support_contact is the phone/contact number, warranty_policy is the warranty info.\\n- If client_config.store_address is present, use it directly to answer location questions. Do NOT say the information is unavailable.\\n- If a specific detail is missing from client_config (e.g., store_location_link is null), only then say that specific detail is not available.\\n- After a store-info answer, do not append a product-search question unless the same message also asked about products.\\nNarrow clarification rules:\\n- Do not ask buying-or-exchange unless intent is truly unclear and there is no useful session context.\\n- If the customer asked about price, ask a narrow follow-up about the model or brand if needed.\\n- If the customer asked available?, use the current item or current flow if present; do not reopen from zero.\\n- If the customer said that one or cheaper one, stay in reference clarification or prior-context continuation; do not reopen with a catalog greeting.\\n- If resolver_output.post_price_mode is price_shown and resolver_output.result_type is single_product: this is a HARD OVERRIDE. Do not add any generic close, any broader question, or any extra sentence. After the price, add ONE blank line, then ONE single short sentence only. That sentence must lead with an exchange value hook and end with 'or more details?' as the only fallback. Do NOT say 'about this phone' or 'about the target phone'. Do NOT write multiple sentences. Do NOT ask a plain question. Frame exchange as a value offer using 'I can show you' or 'I can tell you' language. Use resolver_output.exchange_invitation_variant to pick one of four hook styles: variant 1: 'Tell me your phone  -  I can show you how much you add, or more details?'; variant 2: 'Have a phone? I can tell you how much you add  -  or more details?'; variant 3: 'Want to check how much you would add  -  or more details?'; variant 4: 'I can check the add-on amount if you have a phone  -  or more details?'. Adapt each to natural Amharic while keeping the same short hook structure.\\n- When showing a product price, keep the follow-up focused on whether the customer wants that exact model or wants to compare one closely similar option.\\n- If the customer is in exchange flow, prefer asking for the current phone's model, storage, or ram details rather than broad trade-in questions.\\n- If the customer already has a product in session context and asks about price or availability, continue from that item instead of asking for the model again.\\nStyle rules:\\n- Sound like a practical Ethiopian phone seller on Telegram without forcing sales behavior into every message.\\n- Be short, direct, natural, and sales-aware when the message is actually business-related.\\n- For social or off-topic messages, stay natural and do not drag the reply into phone discovery.\\n- Do not output unrelated acknowledgment-only text for negotiation, pricing, store-info, or refinement messages.\\n- No robotic assistant phrasing.\\n- No broad onboarding copy unless this is truly a new conversation.\\nOutput JSON only." },
